public class BreakMulti {
    public static void main(String[] args) {
        int result = -1;
        search:
        for (int i = 0; i < 4; i++) {
            for (int j = 0; j < 4; j++) {
                if (i * j > 5) {
                    result = i * 10 + j;
                    break search;
                }
            }
        }
        System.out.println(result);
    }
